import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';
const ProductList = () => {
    const { isAdmin, isSeller, isUser } = useAuth();
    const [products, setProducts] = useState([]);
    const [searchId, setSearchId] = useState('');
    const [searchResults, setSearchResults] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        fetchProducts();
    }, []);

    const fetchProducts = async () => {
        try {
            const response = await api.get('/api/products');
            setProducts(response.data);
        } catch (err) {
            setError('Ошибка загрузки товаров');
        } finally {
            setLoading(false);
        }
    };

    // ✅ ГЕНЕРАЦИЯ ТЕСТОВЫХ ТОВАРОВ (Продавец И Админ)
    const handleGenerateTestProducts = async () => {
        const count = prompt('Сколько товаров создать? (1-100)', '10');
        if (!count || count < 1 || count > 100) {
            alert('Введите число от 1 до 100');
            return;
        }

        try {
            await api.post('/api/products/generate', { count: parseInt(count) });
            alert(`✅ Создано ${count} тестовых товаров!`);
            fetchProducts();
        } catch (err) {
            alert('❌ Ошибка: ' + (err.response?.data?.error || err.message));
        }
    };

    const handleSearch = async (e) => {
    e.preventDefault();
    const query = searchId.trim();

    if (!query) {
        setSearchResults(null);
        setError(null);
        return;
    }

    try {
        setError(null);
        // Делаем запрос к нашему новому эндпоинту
        const response = await api.get(`/api/products/search/${encodeURIComponent(query)}`);

        // Сервер вернет массив товаров. Сохраняем его.
        setSearchResults(response.data);
    } catch (err) {
        // Если 404, сервер вернет ошибку. Сбрасываем результаты и показываем текст.
        setSearchResults([]); 
        setError('Товары не найдены');
    }
};

    const handleDelete = async (id) => {
        if (window.confirm('Удалить этот товар?')) {
            try {
                await api.delete(`/api/products/${id}`);
                setProducts(products.filter(p => p.id !== id));
                if (searchResults && searchResults.id === id) {
                    setSearchResults(null);
                }
            } catch (err) {
                alert('Ошибка удаления товара');
            }
        }
    };

    if (loading) return <div>Загрузка...</div>;
    if (error) return <div>{error}</div>;

    return (
        <div style={styles.container}>
            <h1>Список товаров</h1>

            {/* ✅ КНОПКА ГЕНЕРАЦИИ (Продавец И Админ) */}
            {(isSeller || isAdmin) && (
                <button onClick={handleGenerateTestProducts} style={styles.generateButton}>
                    🎲 Сгенерировать тестовые товары
                </button>
            )}

            {/* ===== ПОИСК ПО ID ===== */}
            <form onSubmit={handleSearch} style={styles.searchForm}>
                <input
                    type="text"
                    value={searchId}
                    onChange={(e) => setSearchId(e.target.value)}
                    placeholder="Поиск по ID (например: PROD-ABC123)"
                    style={styles.searchInput}
                />
                <button type="submit" style={styles.searchButton}>🔍 Найти</button>
                <button 
                    type="button" 
                    onClick={() => { setSearchId(''); setSearchResults(null); }}
                    style={styles.clearButton}
                >
                    ✕ Очистить
                </button>
            </form>

 {/* ===== РЕЗУЛЬТАТЫ ПОИСКА ===== */}
            {searchResults && (
                <div style={styles.searchResults}>
                    <h3>Результат поиска:</h3>
                    {searchResults.error ? (
                        <div style={styles.notFound}>{searchResults.error}</div>
                    ) : (
                        <div style={styles.card}>
                            {searchResults.image ? (
                                <img
                                    src={`http://localhost:3000${searchResults.image}`}
                                    alt={searchResults.name}
                                    style={styles.cardImage}
                                />
                            ) : (
                                <div style={styles.noImage}>Нет изображения</div>
                            )}
                            <div style={styles.cardContent}>
                                <h3>{searchResults.name}</h3>
                                <p style={styles.productId}><strong>ID:</strong> {searchResults.id}</p>
                                <p style={styles.price}>${searchResults.price}</p>
                                <p style={styles.description}>{searchResults.description}</p>
                                <div style={styles.cardActions}>
                                    <Link to={`/products/${searchResults.id}`}>
                                        <button style={styles.button}>Просмотр</button>
                                    </Link>
                                    {/* ✅ Редактировать (Продавец И Админ) */}
                                    {(isSeller || isAdmin) && (
                                        <Link to={`/products/${searchResults.id}/edit`}>
                                            <button style={styles.button}>Редактировать</button>
                                        </Link>
                                    )}
                                    {/* ✅ Удалить (ТОЛЬКО АДМИН) */}
                                    {isAdmin && (
                                        <button
                                            onClick={() => handleDelete(searchResults.id)}
                                            style={{ ...styles.button, backgroundColor: '#ff4444' }}
                                        >
                                            Удалить
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            )}


            {/* ===== ВСЕ ТОВАРЫ ===== */}
            <h2>Все товары ({products.length})</h2>

            {/* ✅ Создать товар (Продавец И Админ) */}
            {(isSeller || isAdmin) && (
                <Link to="/products/new">
                    <button style={styles.createButton}>➕ Создать товар</button>
                </Link>
            )}

            <div style={styles.grid}>
                {products.map((product) => (
                    <div key={product.id} style={styles.card}>
                        {product.image ? (
                            <img
                                src={`http://localhost:3000${product.image}`}
                                alt={product.name}
                                style={styles.cardImage}
                            />
                        ) : (
                            <div style={styles.noImage}>Нет изображения</div>
                        )}
                        <div style={styles.cardContent}>
                            <h3>{product.name}</h3>
                            <p style={styles.productId}><strong>ID:</strong> {product.id}</p>
                            <p style={styles.price}>${product.price}</p>
                            <p style={styles.description}>{product.description}</p>
                            <div style={styles.cardActions}>
                                <Link to={`/products/${product.id}`}>
                                    <button style={styles.button}>Просмотр</button>
                                </Link>
                                {/* ✅ Редактировать (Продавец И Админ) */}
                                {(isSeller || isAdmin) && (
                                    <Link to={`/products/${product.id}/edit`}>
                                        <button style={styles.button}>Редактировать</button>
                                    </Link>
                                )}
                                {/* ✅ Удалить (ТОЛЬКО АДМИН) */}
                                {isAdmin && (
                                    <button
                                        onClick={() => handleDelete(product.id)}
                                        style={{ ...styles.button, backgroundColor: '#ff4444' }}
                                    >
                                        Удалить
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

